VALUES
  ('social-worker-moex-05070', 'social-worker', 'social-worker-moex-107-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '未繫安全帶的時候，車內會發出惱人的嗶嗶聲，促使駕駛人繫上安全帶，這種嗶嗶聲屬於：', '["負增強（negative reinforcement）", "消除（extinction）", "正懲罰（positive punishment）", "負懲罰（negative punishment）"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:29+00:00", "source_pdf_sha1": "72531ff92f90", "answer_pdf_sha1": "fbf916b39630", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 38, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05071', 'social-worker', 'social-worker-moex-107-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '你為某一位候選人助選，一開始時你對自己目前所做的事感到不舒服，因為過去你對這位候選人 並無特別好感；但自從為他/她助選後，現在你發現自己對此候選人認同多了，那一種理論能解 釋你態度的轉變？', '["自我知覺理論（self-perception theory）", "社會影響理論（social impact theory）", "自我監控理論（self-monitoring theory）", "認知失諧理論（cognitive dissonance theory）"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:29+00:00", "source_pdf_sha1": "72531ff92f90", "answer_pdf_sha1": "fbf916b39630", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 39, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05072', 'social-worker', 'social-worker-moex-107-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '「戀母情結（Oedipus complex）」容易發生在那一個性心理發展階段？', '["兩性期（genital）", "肛門期（anal）", "口腔期（oral）", "性蕾期（phallic）"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:29+00:00", "source_pdf_sha1": "72531ff92f90", "answer_pdf_sha1": "fbf916b39630", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 40, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05073', 'social-worker', 'social-worker-moex-107-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '下列選項中的成語，何者使用錯誤？', '["你先去探查情況，記得要看風使帆，千萬別打草驚蛇", "這種痛苦的日子，昊天罔極，究竟要到什麼時候才能了脫", "他們夫婦倆一向樂觀，儘管年屆半百，膝下猶虛，也不覺得遺憾", "除了本系課程，他還到幾所名校旁聽，轉益多師，將來必有一番成就"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:29+00:00", "source_pdf_sha1": "650571678696", "answer_pdf_sha1": "4a093209854b", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "107", "s": "0702", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05074', 'social-worker', 'social-worker-moex-107-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '李治平先生接到一封寫著「李治平先生  台啟」的信件，從「啟封詞」的用語判斷，這 應該是下列何人來信？', '["長輩", "平輩", "晚輩", "部屬"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:29+00:00", "source_pdf_sha1": "650571678696", "answer_pdf_sha1": "4a093209854b", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "107", "s": "0702", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05075', 'social-worker', 'social-worker-moex-107-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '「有一次在課堂上，顧先生引用雪萊的〈西風頌〉中的『假如冬天來了，春天還會遠嗎？』 的詩意，用中文寫了『（  ）他風雪（  ）他寒，縱寒已是春寒了』兩句詞。」空格處 應填入何字：', '["奈", "耐", "怨", "愛"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:29+00:00", "source_pdf_sha1": "650571678696", "answer_pdf_sha1": "4a093209854b", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "107", "s": "0702", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05076', 'social-worker', 'social-worker-moex-107-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '張養浩〈中呂‧山坡羊‧潼關懷古〉：「峰巒如聚，波濤如怒，山河表裏潼關路。望西 都，意踟躕，傷心秦漢經行處，宮闕萬間都做了土。興，百姓苦；亡，百姓苦！」 下列何者為作者最深的感歎？', '["秦漢帝國定都關中，雖然表裏山河，形勢險要，最後仍然不免滅亡", "秦漢宮闕，今剩土堆，不知埋藏多少帝王后妃愛情故事，令人唏噓不已", "在這裡不知曾有多少朝代興亡的戰役，但不管結果如何，人民一樣受苦", "「峰巒如聚，波濤如怒」象徵不知曾有多少英雄豪傑，馳騁其間，而今安在"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:29+00:00", "source_pdf_sha1": "650571678696", "answer_pdf_sha1": "4a093209854b", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "107", "s": "0702", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05077', 'social-worker', 'social-worker-moex-107-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '古典小說中，其內容：「以功名富貴為一篇之骨，有心豔功名富貴而媚人下人者，有倚 仗功名富貴而驕人傲人者，有假託無意功名富貴自以為高，被人看破恥笑者。」 依此判斷，該名著為何？', '["《西遊記》", "《水滸傳》", "《儒林外史》", "《聊齋誌異》"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:29+00:00", "source_pdf_sha1": "650571678696", "answer_pdf_sha1": "4a093209854b", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "107", "s": "0702", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05078', 'social-worker', 'social-worker-moex-107-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '「九百年的雪泥，都化盡了 留下最美麗的鴻爪，令人低迴 從此地到瓊州，茫茫煙水 你的魂魄仍賦在波上 長吟：『海南萬里真吾鄉』」 由以上詩句，可推斷作者詠嘆的對象是：', '["屈原", "李白", "蘇軾", "陸游"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:29+00:00", "source_pdf_sha1": "650571678696", "answer_pdf_sha1": "4a093209854b", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "107", "s": "0702", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05079', 'social-worker', 'social-worker-moex-107-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '雖然是暮春，天氣卻炎熱得如暑夏。平快的車廂裡，所有的電風扇都開動了，但是仍有 些旅客用扇子拚命地搧著。……上個星期六，那個宜蘭的小伙子，坐立不安，不能自在 的樣子，幾次想問她話，而又膽懼地畏縮著，最後鼓足了勇氣，說出來的聲音竟是纖細 顫抖的。她沒理他，他羞怯地紅了臉，同時怪不好意思地看看旁人是不是在注意他。她 裝著無意地伸腳去靠他，他動也不敢一動。過些時，稍給他加點壓力，他就變得像灌足 了氣的氣球，搖搖晃晃地，只要一斷線，馬上就會飄上天。結果那人越站跟到羅東，到 了收票柵口，和收票員比手畫腳地說了半天。她遠遠地回頭看了這情形，不禁暗笑起來。 文中「只要一斷線，馬上就會飄上天」是指什麼？', '["火車上灌足了氣的氣球", "火車上男孩顫抖的聲音", "火車上女孩手上的車票", "火車上男孩愛慕的情緒"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:29+00:00", "source_pdf_sha1": "650571678696", "answer_pdf_sha1": "4a093209854b", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "107", "s": "0702", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
